class Solution {
public:
    int guessNumber(int n) {
        int left = 1, right = n;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            int result = guess(mid);
            if (result == 0) return mid;
            if (result < 0) right = mid - 1;
            else left = mid + 1;
        }
        return -1;
    }
};
